        x6_re = rio_re[m*ms+6*ios]; x6_im = rio_im[m*ms+6*ios];
        { double wr = W_re[0], wi = W_im[0], tr = x1_re;
          x1_re = x1_re*wr - x1_im*wi;
          x1_im = tr*wi + x1_im*wr; }
